const k = $json.kpi || {};
const totalCost = parseFloat(k.total_cost_usd || 0);
const aiCost = parseFloat(k.ai_cost_usd || 0);
const rev = parseFloat(k.total_revenue_usd || 0);
const profit = rev - totalCost;
const margin = rev > 0 ? ((profit/rev)*100).toFixed(1) + '%' : 'N/A';
const topCost = (k.top_cost_drivers || []).map(c => '  - ' + (c.vendor||'unknown') + ': $' + parseFloat(c.amount_usd||0).toFixed(2) + ' (' + c.tx_count + ' tx)').join('\n') || '  (no expenses logged)';
const topWf = (k.top_workflows || []).map(w => '  - ' + w.workflow_name + ': ' + w.events + ' events').join('\n') || '  (no events)';
const lines = [
  '*Bridge Daily Finance & KPI Report*',
  '_last 24h UTC_',
  '',
  '*Cost*  Total: $' + totalCost.toFixed(2) + ' | AI: $' + aiCost.toFixed(2) + ' | Other: $' + (totalCost-aiCost).toFixed(2),
  '*Revenue*  Total: $' + rev.toFixed(2) + ' | Profit: $' + profit.toFixed(2) + ' | Margin: ' + margin,
  '',
  '*Top cost drivers*',
  topCost,
  '',
  '*Top workflow activity*',
  topWf,
  '',
  '*Pipeline (24h)*',
  '  Leads: ' + (k.leads_24h||0) + ' | Demos: ' + (k.demos_24h||0) + ' | Outreach: ' + (k.outreach_24h||0) + ' | Paid invoices: ' + (k.invoices_paid_24h||0),
  '',
  '_AI cost is partial — full per-call token logging requires super-agent /chat/direct instrumentation._'
];
return [{json:{telegram_text: lines.join('\n'), kpi: k}}];
